protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // Preserve EF Core 8 discriminator property name (EF Core 9 defaults to "$type").
        // Existing documents and direct SQL queries reference c.Discriminator.
        entity.HasDiscriminator<string>("Discriminator");

        // Preserve EF Core 8 compound id format "Product|123" (EF Core 9 defaults to key-only).
        // Existing 500K documents use the old format; without this, FindAsync/point-reads fail.
        entity.HasRootDiscriminatorInJsonId(true);
    });
}

